import { Injectable, Logger } from "@nestjs/common";

import type { ClientInquiryDto } from "../../dtos/client-inquiry.dto.ts";
import type { ClientInquiryResponseDto } from "../../dtos/client-inquiry-response.dto.ts";
import { DK_API_ENDPOINTS } from "./dk-api-endpoints.ts";
import { DK_RESPONSE_CODES } from "./dk-response-codes.ts";
import { AccountNotFoundException } from "../../exceptions/account-not-found.exception.ts";
import { DKGatewayException } from "../../exceptions/dk-gateway.exception.ts";
import type {
  DKAccountInquiryRequest,
  DKAccountInquiryResponse,
  DKClientInquiryResponse,
} from "./dk-account-inquiry.interface.ts";
import { DKClientService } from "./dk-client.service.ts";

export interface AccountDetails {
  accountNumber: string;
  accountName: string;
  balance?: string;
  inquiryId: string;
  cid?: string;
  hasAccount?: boolean;
  cidNo?: string;
}

@Injectable()
export class DKAccountService {
  private readonly logger = new Logger(DKAccountService.name);

  constructor(private readonly dkClient: DKClientService) {}

  async verifyAccountByCID(cid: string): Promise<AccountDetails> {
    try {
      this.logger.log(`Verifying account for CID: ${cid}`);

      const request = {
        id_type: "CID" as const,
        id_number: cid,
      };

      const response = await this.dkClient.post<DKClientInquiryResponse>(
        DK_API_ENDPOINTS.ACCOUNT.CLIENT_INQUIRY,
        request,
      );

      if (response.response_code !== DK_RESPONSE_CODES.SUCCESS) {
        if (response.response_code === DK_RESPONSE_CODES.NOT_FOUND) {
          throw new AccountNotFoundException(cid);
        }

        throw new DKGatewayException(
          response.response_code,
          response.response_description,
        );
      }

      if (!response.response_data || response.response_data.length === 0) {
        throw new AccountNotFoundException(cid);
      }

      const accountInfo = response.response_data[0]!;

      // Now verify the account and get inquiry ID
      const accountDetails = await this.verifyAccount(
        accountInfo.account_number,
      );

      return {
        ...accountDetails,
        cid,
      };
    } catch (error) {
      this.logger.error(`Failed to verify account for CID: ${cid}`, error);
      throw error;
    }
  }

  async verifyAccount(accountNumber: string): Promise<AccountDetails> {
    try {
      this.logger.log(`Performing account inquiry for: ${accountNumber}`);

      const request: Omit<DKAccountInquiryRequest, "request_id"> = {
        account_number: accountNumber,
      };

      const response = await this.dkClient.post<DKAccountInquiryResponse>(
        DK_API_ENDPOINTS.ACCOUNT.INQUIRY,
        request,
      );

      if (response.response_code !== DK_RESPONSE_CODES.SUCCESS) {
        if (response.response_code === DK_RESPONSE_CODES.NOT_FOUND) {
          throw new AccountNotFoundException(accountNumber);
        }

        throw new DKGatewayException(
          response.response_code,
          response.response_description,
        );
      }

      if (!response.response_data) {
        throw new AccountNotFoundException(accountNumber);
      }

      return {
        accountNumber: response.response_data.account_number,
        accountName: response.response_data.beneficiary_account_name,
        balance: response.response_data.balance_info,
        inquiryId: response.response_data.inquiry_id,
      };
    } catch (error) {
      this.logger.error(`Failed to verify account: ${accountNumber}`, error);
      throw error;
    }
  }

  async verifyAccountByAccountNumber(
    accountNumber: string,
  ): Promise<AccountDetails> {
    try {
      const accountDetails = await this.verifyAccount(accountNumber);
      return {
        ...accountDetails,
        hasAccount: true,
        cidNo: accountDetails.cid, // Map cid to cidNo for consistency
      };
    } catch (error) {
      this.logger.warn(
        `Account not found for account number: ${accountNumber}`,
      );
      return {
        accountNumber,
        accountName: "",
        balance: "BTN: 0.00",
        inquiryId: "",
        hasAccount: false,
        cidNo: "",
      };
    }
  }

  async clientInquiry(
    dto: ClientInquiryDto,
  ): Promise<ClientInquiryResponseDto> {
    try {
      this.logger.log(
        `Performing client inquiry for ${dto.id_type}: ${dto.id_number}`,
      );

      const request = {
        id_type: dto.id_type,
        id_number: dto.id_number,
      };

      const response = await this.dkClient.post<ClientInquiryResponseDto>(
        DK_API_ENDPOINTS.ACCOUNT.CLIENT_INQUIRY,
        request,
      );

      // Log the raw response from DK Gateway
      this.logger.log(
        `DK Gateway raw response: ${JSON.stringify(response, null, 2)}`,
      );

      return response;
    } catch (error) {
      this.logger.error(
        `Failed client inquiry for ${dto.id_type}: ${dto.id_number}`,
        error,
      );
      throw error;
    }
  }
}
